mapper.select:
SELECT content_id AS contentid, title, addr1, first_image1 AS firstimage, latitude AS mapy, longitude AS mapx, a.content_type_id AS contenttypeid, COALESCE(ct.content_type_name, '') AS contentTypeName, area_code AS areacode, si_gun_gu_code AS sigungucode, overview FROM attractions a LEFT JOIN contenttypes ct ON ct.content_type_id = a.content_type_id WHERE 1 = 1
AND a.area_code = #{areaCode}
AND a.si_gun_gu_code = #{gugunCode}
AND a.content_type_id = #{contentTypeId}
AND ( a.title LIKE CONCAT('%', #{keyword}, '%') OR a.addr1 LIKE CONCAT('%', #{keyword}, '%') OR a.overview LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY a.title LIMIT 100
